package com.veetu.vadagai.auth;import jakarta.servlet.*;import jakarta.servlet.http.*;import lombok.RequiredArgsConstructor;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.security.core.userdetails.UserDetailsService;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import java.io.IOException;
@Component @RequiredArgsConstructor public class JwtAuthFilter extends OncePerRequestFilter{private final JwtService jwt;private final UserDetailsService uds;protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String h=req.getHeader("Authorization");if(h!=null&&h.startsWith("Bearer ")&&SecurityContextHolder.getContext().getAuthentication()==null){try{String email=jwt.subject(h.substring(7));var d=uds.loadUserByUsername(email);SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(d,null,d.getAuthorities()));}catch(Exception ignored){}}chain.doFilter(req,res);}}
